import{_ as e,o as a,c as i,a2 as t}from"./chunks/framework.CZqXuAiL.js";const k=JSON.parse('{"title":"Rate-Based Detection","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/detection-engine/rate-based.md","filePath":"openshield-xdp/detection-engine/rate-based.md","lastUpdated":1782455978000}'),n={name:"openshield-xdp/detection-engine/rate-based.md"};function d(o,s,p,h,l,r){return a(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="rate-based-detection" tabindex="-1">Rate-Based Detection <a class="header-anchor" href="#rate-based-detection" aria-label="Permalink to &quot;Rate-Based Detection&quot;">​</a></h1><p>Per-IP, per-second rate thresholds with additive suspicion scoring. When an IP exceeds a threshold, points are added to its suspicion score. When the cumulative score reaches the ban threshold, the IP is banned.</p><h2 id="how-scoring-works" tabindex="-1">How scoring works <a class="header-anchor" href="#how-scoring-works" aria-label="Permalink to &quot;How scoring works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Window (1 second):</span></span>
<span class="line"><span>  IP sends N packets, M bytes, T TCP, U UDP, I ICMP, S SYN</span></span>
<span class="line"><span>  For each threshold exceeded → add score to suspicion_score</span></span>
<span class="line"><span>  suspicion_score decays by suspicion_decay% each window</span></span>
<span class="line"><span>  When suspicion_score ≥ suspicion_threshold → ban</span></span></code></pre></div><h2 id="thresholds-and-scores" tabindex="-1">Thresholds and scores <a class="header-anchor" href="#thresholds-and-scores" aria-label="Permalink to &quot;Thresholds and scores&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Default threshold</th><th>Default score</th><th>Config field</th></tr></thead><tbody><tr><td>Packets/s</td><td>1,000</td><td>20</td><td><code>pps_threshold</code> / <code>pps_score</code></td></tr><tr><td>Bytes/s</td><td>10 MB/s</td><td>20</td><td><code>bps_threshold</code> / <code>bps_score</code></td></tr><tr><td>TCP/s</td><td>800</td><td>15</td><td><code>tcp_pps_threshold</code> / <code>tcp_pps_score</code></td></tr><tr><td>UDP/s</td><td>500</td><td>15</td><td><code>udp_pps_threshold</code> / <code>udp_pps_score</code></td></tr><tr><td>ICMP/s</td><td>100</td><td>25</td><td><code>icmp_pps_threshold</code> / <code>icmp_pps_score</code></td></tr><tr><td>SYN/s</td><td>200</td><td>30</td><td><code>syn_pps_threshold</code> / <code>syn_pps_score</code></td></tr></tbody></table><p>SYN floods are scored higher by default (30 points vs 20 for PPS) because they are almost always malicious at high rates.</p><h2 id="check-frequency" tabindex="-1">Check frequency <a class="header-anchor" href="#check-frequency" aria-label="Permalink to &quot;Check frequency&quot;">​</a></h2><p>Threshold scoring evaluates on two triggers:</p><ol><li><strong>Window reset</strong> — every 1 second, the per-IP window counters become the rate</li><li><strong>Per-packet</strong> — every 256th packet (<code>pkt_count &amp; 0xFF == 0</code>) triggers an evaluation</li></ol><p>This catches rate violations within ~256 packets instead of waiting the full second.</p><h2 id="suspicion-decay" tabindex="-1">Suspicion decay <a class="header-anchor" href="#suspicion-decay" aria-label="Permalink to &quot;Suspicion decay&quot;">​</a></h2><p>Each window reset, the suspicion score is multiplied by <code>suspicion_decay</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">static</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  suspicion_decay</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Keep 50% per second</span></span></code></pre></div><p>A clean IP&#39;s score halves each second. After 3–5 windows of normal traffic, a one-time burst is fully decayed.</p><h2 id="repeat-offenders" tabindex="-1">Repeat offenders <a class="header-anchor" href="#repeat-offenders" aria-label="Permalink to &quot;Repeat offenders&quot;">​</a></h2><p>The effective ban threshold tightens for repeat offenders:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>effective = suspicion_threshold * 2 / (2 + ban_count)</span></span>
<span class="line"><span>Minimum floor = 10</span></span></code></pre></div><p>First ban: full threshold (default 100). Third ban: drops to 40. The floor of 10 prevents over-aggressive banning.</p><h2 id="token-bucket-alternative" tabindex="-1">Token bucket alternative <a class="header-anchor" href="#token-bucket-alternative" aria-label="Permalink to &quot;Token bucket alternative&quot;">​</a></h2><p>Set <code>rate_limit_mode: token_bucket</code> for a different model:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">static</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  rate_limit_mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">token_bucket</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  token_rate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Tokens refilled per second per IP</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  token_burst</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # Max burst before draining</span></span></code></pre></div><p>Tokens refill proportionally to elapsed nanoseconds. First packet seeds the bucket. Each packet drains 1 token. Drop when empty.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">static</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  pps_threshold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  syn_pps_threshold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">200</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  suspicion_threshold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ban_duration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3600</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  suspicion_decay</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.5</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  rate_limit_mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">threshold</span></span></code></pre></div><h2 id="related-pages" tabindex="-1">Related pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related pages&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/detection-engine/l3-l4">L2/L3/L4 Validation</a> · <a href="/pingless-studios-docs/openshield-xdp/mitigation/overview">Mitigation</a></p>`,27)])])}const g=e(n,[["render",d]]);export{k as __pageData,g as default};
